import json

# Load files
with open('manifest.json', 'r') as f:
    manifest = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

# Manual validation
errors = []

# Check required properties
if 'release' not in manifest:
    errors.append('Missing required property: release')
if 'components' not in manifest:
    errors.append('Missing required property: components')

# Check additionalProperties at root level
extra_props = set(manifest.keys()) - {'release', 'components'}
if extra_props:
    errors.append(f'additionalProperties violation at root: {extra_props}')

# Check release pattern
import re
if 'release' in manifest:
    if not isinstance(manifest['release'], str):
        errors.append('release must be a string')
    elif not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+\$', manifest['release']):
        errors.append(f'release does not match pattern: {manifest[\"release\"]}')

# Check components
if 'components' in manifest:
    if not isinstance(manifest['components'], list):
        errors.append('components must be an array')
    else:
        if len(manifest['components']) != 3:
            errors.append(f'components must have exactly 3 items, got {len(manifest[\"components\"])}')

        seen_names = set()
        for i, comp in enumerate(manifest['components']):
            if not isinstance(comp, dict):
                errors.append(f'components[{i}] must be an object')
                continue

            # Check required properties
            if 'name' not in comp or 'version' not in comp:
                errors.append(f'components[{i}] missing required properties')

            # Check no extra properties
            extra_keys = set(comp.keys()) - {'name', 'version'}
            if extra_keys:
                errors.append(f'components[{i}] additionalProperties violation: {extra_keys}')

            # Check name is string
            if 'name' in comp and not isinstance(comp['name'], str):
                errors.append(f'components[{i}].name must be a string')

            # Check version matches semver pattern
            if 'version' in comp:
                if not isinstance(comp['version'], str):
                    errors.append(f'components[{i}].version must be a string')
                elif not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+\$', comp['version']):
                    errors.append(f'components[{i}].version does not match semver: {comp[\"version\"]}')

            # Check uniqueness
            if 'name' in comp:
                if comp['name'] in seen_names:
                    errors.append(f'components[{i}] is a duplicate: {comp[\"name\"]}')
                seen_names.add(comp['name'])

if errors:
    print('✗ VALIDATION FAILED:')
    for err in errors:
        print(f'  - {err}')
    exit(1)
else:
    print('✓ manifest.json PASSES schema validation')
    print('manifest.json content:')
    print(json.dumps(manifest, indent=2))
"

